import multiprocessing

def producer(queue):
    for i in range(5):
        queue.put(i)
    queue.put(None)  # Sentinel to indicate end of data

def consumer(queue):
    while True:
        item = queue.get()
        if item is None:
            break
        print(f"Processing item: {item}")
    print("Consumer has finished processing.")

